<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  body {
    background: #1e1e1e;
    color: #eee;
    font-family: sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 20px;
    margin: 0;
    min-height: 100vh;
  }
  #bars {
    display: flex;
    align-items: flex-end;
    height: 300px;
    width: 90%;
    max-width: 800px;
    background: #2d2d2d;
    border-radius: 4px;
    padding: 10px;
    gap: 1px;
    box-sizing: border-box;
    margin-bottom: 20px;
  }
  .bar {
    flex: 1;
    background: linear-gradient(to top, #4ecdc4, #45aaf2);
    border-radius: 2px 2px 0 0;
    transition: height 0.05s ease-out;
    min-height: 1px;
  }
  #controls {
    display: flex;
    gap: 10px;
  }
  button {
    padding: 10px 20px;
    background: #333;
    color: #eee;
    border: 1px solid #555;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    transition: background 0.2s;
  }
  button:hover {
    background: #444;
  }
  button:active {
    background: #555;
  }
</style>
</head>
<body>
<div id="bars"></div>
<div id="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>
<script>
  // State
  let arr = [];
  let initialArray = [];
  let sortState = { i: 0, j: 0, n: 0 };
  let isAnimating = false;

  const barsContainer = document.getElementById('bars');

  // Generate random array
  function generateArray(size = 50) {
    const a = [];
    for (let i = 0; i < size; i++) {
      a.push(Math.floor(Math.random() * 100) + 1);
    }
    return a;
  }

  // Render bars
  function render() {
    barsContainer.innerHTML = '';
    if (arr.length === 0) return;
    const max = Math.max(...arr);
    arr.forEach(value => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = `${(value / max) * 100}%`;
      barsContainer.appendChild(bar);
    });
  }

  // Reset sorting indices
  function resetSortState() {
    sortState.i = 0;
    sortState.j = 0;
    sortState.n = arr.length;
  }

  // Check if sorted
  function sorted() {
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] > arr[i + 1]) return false;
    }
    return true;
  }

  // Perform one step of bubble sort
  function sortStep() {
    if (sorted()) return true;
    if (sortState.n !== arr.length) resetSortState();

    // Compare and swap if needed
    if (arr[sortState.j] > arr[sortState.j + 1]) {
      [arr[sortState.j], arr[sortState.j + 1]] = [arr[sortState.j + 1], arr[sortState.j]];
    }

    // Advance indices
    sortState.j++;
    if (sortState.j >= sortState.n - sortState.i - 1) {
      sortState.i++;
      sortState.j = 0;
    }

    // Check completion
    if (sortState.i >= sortState.n - 1 || sorted()) {
      return true;
    }
    return false;
  }

  // Shuffle array
  function shuffleArray() {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    resetSortState();
    render();
  }

  // Set array from outside
  function setArray(a) {
    arr = a.slice();
    resetSortState();
    render();
  }

  // Get current array
  function getArray() {
    return arr.slice();
  }

  // Animation loop
  function animateSort() {
    if (!isAnimating) return;
    const done = sortStep();
    render();
    if (!done) {
      requestAnimationFrame(animateSort);
    } else {
      isAnimating = false;
    }
  }

  // Event listeners
  document.getElementById('sort').addEventListener('click', () => {
    if (isAnimating) return;
    isAnimating = true;
    animateSort();
  });

  document.getElementById('shuffle').addEventListener('click', () => {
    if (isAnimating) return;
    shuffleArray();
  });

  document.getElementById('reset').addEventListener('click', () => {
    if (isAnimating) return;
    setArray(initialArray);
  });

  // Initialize
  initialArray = generateArray(50);
  arr = initialArray.slice();
  resetSortState();
  render();

  // Expose API for grading
  window.viz = {
    array: getArray,
    setArray,
    sortStep,
    sorted
  };
</script>
</body>
</html>
